#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main(void) {
    setbuf(stdout, NULL);
    printf("Parent PID: %d\n", getpid());

    pid_t child = fork();
    if (child == -1) {
        perror("fork");
        return 1;
    }

    if (child == 0) {
        /* Processus enfant */
        printf("Child: my PID=%d, parent PID=%d\n", getpid(), getppid());
        _exit(42);
    }

    /* Processus parent */
    int status;
    waitpid(child, &status, 0);
    if (WIFEXITED(status))
        printf("Parent: child %d exited with code %d\n", child, WEXITSTATUS(status));

    return 0;
}

